args.sparql:
SELECT ?film WHERE {
  ?film wdt:P31 wd:Q11424.
  ?film wdt:P577 ?releaseYear.
  FILTER (YEAR(?releaseYear) = 2007)
  ?film wdt:P1346 wd:Q106800.
}

SELECT DISTINCT ?film WHERE {
  ?film p:P1346 ?awardStatement.
  ?awardStatement ps:P1346 wd:Q106800.
  ?awardStatement pq:P585 ?date.
  FILTER (YEAR(?date) = 2007)
}
